    let blocked: HashSet<String> = load_registry().blocked.into_iter().collect();

    // Scan common project directories
    let scan_dirs = vec![
        PathBuf::from(&home).join("Projects"),
        PathBuf::from(&home).join("code"),
        PathBuf::from(&home).join("src"),
        PathBuf::from(&home).join("dev"),
    ];

    for dir in scan_dirs {
        if dir.exists() {
            if let Ok(entries) = fs::read_dir(&dir) {
                for entry in entries.flatten() {
                    let path = entry.path();
                    if path.is_dir()
                        && !is_git_worktree(&path)
                        && is_entire_enabled(&path.to_string_lossy())
                    {
                        let s = path.to_string_lossy().to_string();
                        if !blocked.contains(&s) && seen.insert(s.clone()) {
                            repos.push(s);
                        }
                    }
                }
            }
        }
    }

    // Merge in manually registered repos
    for registered in load_registered_repos() {
        if !blocked.contains(&registered) && seen.insert(registered.clone()) {
            // Only add if the repo still exists and is still enabled
            if Path::new(&registered).is_dir()
                && !is_git_worktree(Path::new(&registered))
                && is_entire_enabled(&registered)
            {
                repos.push(registered);
            }
        }
    }

    repos
}

// --- App-wide settings persistence ---

#[derive(Debug, Serialize, Deserialize, Clone, Default)]
pub struct AppSettings {
    pub anthropic_api_key: Option<String>,
    pub worktree_base_path: Option<String>,
}

fn app_settings_path() -> PathBuf {
    let home = dirs_next().unwrap_or_default();
    PathBuf::from(home).join(".entire").join("app-settings.json")
}

pub fn read_app_settings() -> AppSettings {
    let path = app_settings_path();
    let content = match fs::read_to_string(&path) {
        Ok(c) => c,
        Err(_) => return AppSettings::default(),
    };
    serde_json::from_str(&content).unwrap_or_default()
}

pub fn save_app_settings(settings: &AppSettings) -> Result<(), String> {
    let path = app_settings_path();
    if let Some(parent) = path.parent() {
        fs::create_dir_all(parent).map_err(|e| format!("Failed to create ~/.entire: {}", e))?;
    }
    let content =
        serde_json::to_string_pretty(settings).map_err(|e| format!("Failed to serialize: {}", e))?;
    fs::write(&path, content).map_err(|e| format!("Failed to write app settings: {}", e))
}

fn dirs_next() -> Option<String> {
    std::env::var("HOME").ok()
}

